/* global Office */

Office.onReady(() => {
  // If needed, Office.js is ready to be called.
});

/**
 * Shows a notification when the add-in command is executed.
 * @param event {Office.AddinCommands.Event}
 */
function action(event) {
  // For Excel commands, open the taskpane. Avoid using Mailbox/Outlook APIs here.
  try {
    if (Office && Office.addin && typeof Office.addin.showAsTaskpane === "function") {
      Office.addin.showAsTaskpane();
    } else if (Office && Office.context && Office.context.ui && typeof Office.context.ui.displayDialogAsync === "function") {
      // Fallback: open a dialog if taskpane API not available
      Office.context.ui.displayDialogAsync("./taskpane.html");
    }
  } catch (e) {
    console.warn("Unable to open taskpane from command:", e);
  }

  // Indicate the add-in command function is complete.
  event.completed();
}

// Register the function with Office.
Office.actions.associate("action", action);
